import React, { useEffect, useState, useCallback } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X } from 'lucide-react';
import toast from 'react-hot-toast';

/**
 * VAULT_PAGE: SECURE_STRATEGY_STORAGE
 * Central interface for managing agent-generated portfolios.
 */
const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  // --- 1. DATA PARSING & SAFETY ---
  const safeParseHoldings = useCallback((data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("VAULT_CORRUPTION_ERROR:", e);
      return [];
    }
  }, []);

  // --- 2. CORE ACTIONS ---
  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Delete this record?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) {
      toast.error("WIPE_FAILED: DB_LOCK");
    }
  };

  const handleDownload = async (item) => {
    const toastId = toast.loading("SYNTHESIZING_PDF...");
    try {
      const { data } = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([data], { type: 'application/pdf' }));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Export_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      
      // Cleanup protocols
      link.remove();
      window.URL.revokeObjectURL(url); 
      toast.success("DOWNLOAD_READY", { id: toastId });
    } catch (err) {
      toast.error("EXPORT_FAILED", { id: toastId });
    }
  };

  // --- 3. LIFECYCLE & EVENTS ---
  useEffect(() => {
    fetchHistory();
    const handleEsc = (e) => e.key === 'Escape' && setSelectedItem(null);
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  useEffect(() => {
    document.body.style.overflow = selectedItem ? 'hidden' : 'unset';
  }, [selectedItem]);

  if (loading) return <div style={styles.centerContainer}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div style={styles.pageWrapper} className="reveal-node">
      <header style={styles.header}>
        <h2 style={styles.headerTitle}>
          <Archive size={20} color="var(--accent-primary)" /> STRATEGY_VAULT
        </h2>
        <span style={styles.countBadge}>{history.length} NODES_ACTIVE</span>
      </header>

      {history.length === 0 ? (
        <div style={styles.emptyContainer}>
          <p>NO_RECORDS_FOUND. INITIALIZE_NEW_STRATEGY_TO_PROCEED.</p>
        </div>
      ) : (
        <div style={styles.listGrid}>
          {history.map((item) => (
            <StrategyCard 
              key={item.id}
              item={item}
              parse={safeParseHoldings}
              onPreview={() => setSelectedItem(item)}
              onDownload={() => handleDownload(item)}
              onDelete={() => handleDelete(item.id)}
            />
          ))}
        </div>
      )}

      {selectedItem && (
        <PreviewModal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
        />
      )}
    </div>
  );
};

// --- SUB-COMPONENT: STRATEGY CARD ---
const StrategyCard = ({ item, parse, onPreview, onDownload, onDelete }) => (
  <div style={styles.card}>
    <div style={{ flex: 1 }}>
      <div style={styles.metaRow}>
        <span style={styles.metaText}><Calendar size={10}/> {new Date(item.created_at).toLocaleDateString()}</span>
        <span style={styles.riskBadge}><ShieldCheck size={10}/> RISK_{item.risk_score}</span>
      </div>
      <h4 style={styles.cardTitle}>{item.goal}</h4>
      <div style={styles.tickerCloud}>
        {parse(item.holdings).map((t, i) => (
          <span key={i} style={styles.tickerTag}>{t}</span>
        ))}
      </div>
    </div>
    <div style={styles.buttonCol}>
      <button onClick={onPreview} style={styles.iconBtn} title="View Details"><Eye size={18}/></button>
      <button onClick={onDownload} style={styles.iconBtn} title="Export PDF"><Download size={18}/></button>
      <button onClick={onDelete} style={styles.deleteBtn} title="Wipe Node"><Trash2 size={18}/></button>
    </div>
  </div>
);

// --- SUB-COMPONENT: PREVIEW MODAL ---
const PreviewModal = ({ item, onClose }) => (
  <div style={styles.modalOverlay} onClick={onClose}>
    <div style={styles.modalContent} onClick={e => e.stopPropagation()}>
      <div style={styles.modalHeader}>
        <h3 style={styles.modalTitle}>NODE_PREVIEW // {item.id}</h3>
        <button onClick={onClose} style={styles.modalCloseBtn}><X size={20}/></button>
      </div>
      <div style={styles.modalBody}>
        <label style={styles.label}>STRATEGY_SUMMARY</label>
        <p style={styles.paragraph}>{item.summary}</p>
        <div style={styles.divider} />
        <label style={styles.label}>AGENTIC_RATIONALE</label>
        <p style={styles.paragraph}>{item.rationale}</p>
      </div>
    </div>
  </div>
);

// --- STYLESHEET ---
const styles = {
  pageWrapper: { padding: '2rem 1.5rem', maxWidth: '1000px', margin: '0 auto' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1rem' },
  headerTitle: { color: 'var(--text-primary)', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.1rem', letterSpacing: '0.1em' },
